_HOOK = os.path.normpath(os.path.join(os.path.dirname(__file__), "..", "..", "..", "hooks", "pretool-bash-safety.sh"))


def _run_hook(command, agent_id="test-agent-ac01"):
    payload = json.dumps({
        "tool_name": "Bash",
        "tool_input": {"command": command},
        "agent_id": agent_id,
    })
    result = subprocess.run(
        ["/bin/bash", _HOOK],
        input=payload, capture_output=True, text=True
    )
    return result.returncode, result.stdout + result.stderr


